const themeToggler=document.getElementById("theme-toggler");const toggleTheme=()=>{const body=document.body;const nav=document.querySelector("nav");const isLight=body.classList.toggle("light");body.classList.toggle("dark",!isLight);nav.classList.toggle("light",isLight);nav.classList.toggle("dark",!isLight);themeToggler.textContent=isLight?"Switch to Dark Mode":"Switch to Light Mode";localStorage.setItem("theme",isLight?"light":"dark")};document.addEventListener("DOMContentLoaded",(()=>{const savedTheme=localStorage.getItem("theme")||"light";document.body.classList.add(savedTheme);document.querySelector("nav").classList.add(savedTheme);themeToggler.textContent=savedTheme==="light"?"Switch to Dark Mode":"Switch to Light Mode";themeToggler.addEventListener("click",toggleTheme);document.querySelectorAll("nav a").forEach((anchor=>{anchor.addEventListener("click",(e=>{e.preventDefault();const targetId=anchor.getAttribute("href");const targetSection=document.querySelector(targetId);if(targetSection){targetSection.scrollIntoView({behavior:"smooth",block:"start"})}}))}));const form=document.querySelector("#contact form");if(form){form.addEventListener("submit",(async e=>{e.preventDefault();const formData=new FormData(form);try{const response=await fetch(form.action,{method:"POST",body:formData,headers:{Accept:"application/json"}});if(response.ok){alert("Thank you for your message! I'll get back to you soon.");form.reset()}else{alert("There was a problem submitting your message. Please try again.")}}catch(error){alert("There was a problem submitting your message. Please try again.")}}))}const fadeInEffect=()=>{const sections=document.querySelectorAll("section");const navLinks=document.querySelectorAll("nav ul li a");const options={root:null,rootMargin:"0px",threshold:.1};const observer=new IntersectionObserver((entries=>{entries.forEach((entry=>{if(entry.isIntersecting){entry.target.classList.add("visible");observer.unobserve(entry.target)}}))}),options);sections.forEach((section=>{section.classList.add("fade-in");observer.observe(section)}));const highlightNav=()=>{let index=sections.length;while(--index&&window.scrollY+50<sections[index].offsetTop){}navLinks.forEach((link=>link.classList.remove("active")));if(navLinks[index]){navLinks[index].classList.add("active")}};window.addEventListener("scroll",highlightNav)};fadeInEffect();const scrollToTopButton=document.getElementById("scrollToTop");window.onscroll=function(){if(document.body.scrollTop>20||document.documentElement.scrollTop>20){scrollToTopButton.style.display="block"}else{scrollToTopButton.style.display="none"}};scrollToTopButton.addEventListener("click",(()=>{document.body.scrollTop=0;document.documentElement.scrollTop=0}))}));